import React from "react"

import Home from "./pages/Home"
import SignUp from "./pages/SignUp"
import Auth from "./pages/Auth"
import NotFound from "./pages/NotFound"
import { Routes, Route, BrowserRouter } from 'react-router-dom';
// import axios from "axios"


class App extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            users: [],
            cur_user: {
                id: 0,
                name: '',
                password: '',
                isAuth: false
            }
        }
        this.addUser = this.addUser.bind(this)
    }
    render() {
        return (
            <BrowserRouter>
                <Routes>
                    <Route path="/reg" render={() => <SignUp onAdd={this.addUser} />} />
                    <Route path="/" Component={Auth} />
                    {this.state.cur_user.isAuth && <Route path="home" Component={Home} />}
                    <Route path="*" Component={NotFound} />
                </Routes>
            </BrowserRouter>
        )
    }
    async addUser(user) {
        const new_id = this.state.users.length + 1;
        const new_user = {id: new_id, name: user.name, password: user.password, isAuth: true}

        this.setState({cur_user: new_user})
        this.setState({users: [...this.state.users, new_user]})
    }
}



export default App
